export { default as MotionGrid } from "./motion-grid.svelte";
export { default as MotionGridCells } from "./motion-grid-cells.svelte";

export type {
	FrameDot,
	Frame,
	Frames,
	MotionGridContextType,
	MotionGridCellMotionProps,
	MotionGridProps,
	MotionGridCellsProps,
} from "./types";

import type { MotionHTMLAttributes } from "motion-sv";
import type { MotionProps } from "motion-sv";
import type { Snippet } from "svelte";

export type FrameDot = [number, number];
export type Frame = FrameDot[];
export type Frames = Frame[];

export type MotionGridContextType = {
	index: () => number;
	cols: () => number;
	rows: () => number;
	frames: () => Frames;
	duration: () => number;
	animate: () => boolean;
};

export type MotionGridCellMotionProps = Omit<MotionProps, "children"> & MotionHTMLAttributes<"div">;

export type MotionGridProps = Omit<MotionProps, "children" | "animate"> &
	MotionHTMLAttributes<"div"> & {
		gridSize: [number, number];
		frames: Frames;
		duration?: number;
		animate?: boolean;
		child?: Snippet<[{ props: MotionGridCellMotionProps }]>;
		children?: Snippet;
	};

export type MotionGridCellsProps = Omit<MotionProps, "children"> &
	MotionHTMLAttributes<"div"> & {
		activeProps?: MotionGridCellMotionProps;
		inactiveProps?: MotionGridCellMotionProps;
	};

import { getContext, setContext } from "svelte";
import type { MotionGridContextType } from "./types";

const MOTION_GRID_CONTEXT_KEY = Symbol("motion-grid-context");

export function setMotionGridContext(value: MotionGridContextType): MotionGridContextType {
	setContext(MOTION_GRID_CONTEXT_KEY, value);
	return value;
}

export function useMotionGridContext(): MotionGridContextType {
	const context = getContext<MotionGridContextType>(MOTION_GRID_CONTEXT_KEY);
	if (!context) {
		throw new Error("MotionGridCells must be used within a MotionGrid provider");
	}
	return context;
}
